CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  username VARCHAR(30) UNIQUE NOT NULL,
  email VARCHAR(120) UNIQUE NOT NULL,
  password_hash VARCHAR(256) NOT NULL,
  display_name VARCHAR(60),
  bio TEXT DEFAULT '',
  avatar_url VARCHAR(512) DEFAULT '',
  created_at TIMESTAMP DEFAULT NOW()
);

CREATE TABLE posts (
  id SERIAL PRIMARY KEY,
  author_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  body TEXT NOT NULL,
  image_url VARCHAR(512),
  created_at TIMESTAMP DEFAULT NOW()
);
CREATE INDEX idx_posts_author ON posts(author_id);
CREATE INDEX idx_posts_created ON posts(created_at DESC);

CREATE TABLE follows (
  follower_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  following_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  created_at TIMESTAMP DEFAULT NOW(),
  PRIMARY KEY (follower_id, following_id)
);
CREATE INDEX idx_follows_following ON follows(following_id);

CREATE TABLE likes (
  user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  post_id INTEGER NOT NULL REFERENCES posts(id) ON DELETE CASCADE,
  created_at TIMESTAMP DEFAULT NOW(),
  PRIMARY KEY (user_id, post_id)
);

CREATE TABLE comments (
  id SERIAL PRIMARY KEY,
  post_id INTEGER NOT NULL REFERENCES posts(id) ON DELETE CASCADE,
  author_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  parent_id INTEGER REFERENCES comments(id) ON DELETE CASCADE,
  body TEXT NOT NULL,
  created_at TIMESTAMP DEFAULT NOW()
);
CREATE INDEX idx_comments_post ON comments(post_id);

from flask import Blueprint, request, jsonify
from flask_jwt_extended import (
    create_access_token, create_refresh_token,
    jwt_required, get_jwt_identity
)
from werkzeug.security import generate_password_hash, check_password_hash
from db import get_db

auth_bp = Blueprint("auth", __name__)

@auth_bp.route("/register", methods=["POST"])
def register():
    data = request.get_json()
    username = data.get("username", "").strip()
    email = data.get("email", "").strip().lower()
    password = data.get("password", "")

    if not username or not email or len(password) < 8:
        return jsonify(error="Invalid input"), 400

    pw_hash = generate_password_hash(password)
    db = get_db()
    cur = db.cursor()
    try:
        cur.execute(
            "INSERT INTO users (username, email, password_hash) VALUES (%s, %s, %s) RETURNING id",
            (username, email, pw_hash),
        )
        user_id = cur.fetchone()[0]
        db.commit()
    except Exception:
        db.rollback()
        return jsonify(error="Username or email already taken"), 409

    access = create_access_token(identity=str(user_id))
    refresh = create_refresh_token(identity=str(user_id))
    return jsonify(access_token=access, refresh_token=refresh, user_id=user_id), 201

@auth_bp.route("/login", methods=["POST"])
def login():
    data = request.get_json()
    db = get_db()
    cur = db.cursor()
    cur.execute("SELECT id, password_hash FROM users WHERE email = %s", (data["email"].lower(),))
    row = cur.fetchone()
    if not row or not check_password_hash(row[1], data["password"]):
        return jsonify(error="Invalid credentials"), 401

    access = create_access_token(identity=str(row[0]))
    refresh = create_refresh_token(identity=str(row[0]))
    return jsonify(access_token=access, refresh_token=refresh, user_id=row[0])

@auth_bp.route("/refresh", methods=["POST"])
@jwt_required(refresh=True)
def refresh():
    identity = get_jwt_identity()
    access = create_access_token(identity=identity)
    return jsonify(access_token=access)

import { createContext, useContext, useState, useCallback, ReactNode } from 'react';

interface AuthState {
  accessToken: string | null;
  userId: number | null;
}

interface AuthContextType extends AuthState {
  login: (access: string, refresh: string, uid: number) => void;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [auth, setAuth] = useState<AuthState>(() => ({
    accessToken: localStorage.getItem('access_token'),
    userId: Number(localStorage.getItem('user_id')) || null,
  }));

  const login = useCallback((access: string, refresh: string, uid: number) => {
    localStorage.setItem('access_token', access);
    localStorage.setItem('refresh_token', refresh);
    localStorage.setItem('user_id', String(uid));
    setAuth({ accessToken: access, userId: uid });
  }, []);

  const logout = useCallback(() => {
    localStorage.clear();
    setAuth({ accessToken: null, userId: null });
  }, []);

  return (
    <AuthContext.Provider value={{ ...auth, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used inside AuthProvider');
  return ctx;
};

import { useState } from 'react';
import { api } from '../utils/api';

interface Post {
  id: number;
  author_id: number;
  username: string;
  avatar_url: string;
  body: string;
  image_url: string | null;
  created_at: string;
  like_count: number;
  comment_count: number;
  liked: boolean;
}

export default function PostCard({ post }: { post: Post }) {
  const [liked, setLiked] = useState(post.liked);
  const [likeCount, setLikeCount] = useState(post.like_count);

  const handleLike = async () => {
    // Optimistic update
    setLiked((prev) => !prev);
    setLikeCount((prev) => prev + (liked ? -1 : 1));
    try {
      const res = await api.post(`/posts/${post.id}/like`);
      setLiked(res.data.liked);
      setLikeCount(res.data.like_count);
    } catch {
      // Revert on error
      setLiked(post.liked);
      setLikeCount(post.like_count);
    }
  };

  return (
    <article className="post-card">
      <header className="post-header">
        <img src={post.avatar_url || '/default-avatar.png'} alt="" className="avatar" />
        <div>
          <strong>{post.username}</strong>
          <time>{new Date(post.created_at).toLocaleDateString()}</time>
        </div>
      </header>
      <p className="post-body">{post.body}</p>
      {post.image_url && <img src={post.image_url} alt="" className="post-image" />}
      <footer className="post-actions">
        <button onClick={handleLike} className={liked ? 'liked' : ''}>
          {liked ? '\u2764\uFE0F' : '\u2661'} {likeCount}
        </button>
        <button>\uD83D\uDCAC {post.comment_count}</button>
      </footer>
    </article>
  );
}

import { useState, useEffect, useRef, useCallback } from 'react';
import PostCard from './PostCard';
import { api } from '../utils/api';

interface Post {
  id: number;
  author_id: number;
  username: string;
  avatar_url: string;
  body: string;
  image_url: string | null;
  created_at: string;
  like_count: number;
  comment_count: number;
  liked: boolean;
}

export default function Feed() {
  const [posts, setPosts] = useState<Post[]>([]);
  const [hasMore, setHasMore] = useState(true);
  const [loading, setLoading] = useState(false);
  const loaderRef = useRef<HTMLDivElement>(null);

  const loadMore = useCallback(async () => {
    if (loading || !hasMore) return;
    setLoading(true);
    const lastId = posts.length > 0 ? posts[posts.length - 1].id : undefined;
    const params = lastId ? `?before=${lastId}&limit=20` : '?limit=20';
    try {
      const res = await api.get(`/posts/feed${params}`);
      setPosts((prev) => [...prev, ...res.data.posts]);
      setHasMore(res.data.has_more);
    } catch (err) {
      console.error('Failed to load feed', err);
    } finally {
      setLoading(false);
    }
  }, [posts, loading, hasMore]);

  // Intersection Observer for infinite scroll
  useEffect(() => {
    const el = loaderRef.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      (entries) => { if (entries[0].isIntersecting) loadMore(); },
      { threshold: 0.5 }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, [loadMore]);

  // Initial load
  useEffect(() => { loadMore(); }, []);  // eslint-disable-line react-hooks/exhaustive-deps

  return (
    <div className="feed">
      {posts.map((p) => <PostCard key={p.id} post={p} />)}
      <div ref={loaderRef} className="loader">
        {loading && <p>Loading...</p>}
        {!hasMore && <p>You're all caught up!</p>}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { api } from '../utils/api';

interface Comment {
  id: number;
  author_id: number;
  username: string;
  body: string;
  parent_id: number | null;
  created_at: string;
  children: Comment[];
}

function CommentItem({ comment, postId, onReply }: {
  comment: Comment; postId: number; onReply: (c: Comment) => void;
}) {
  const [replying, setReplying] = useState(false);
  const [text, setText] = useState('');

  const submit = async () => {
    if (!text.trim()) return;
    const res = await api.post(`/posts/${postId}/comments`, {
      body: text, parent_id: comment.id,
    });
    onReply({ ...res.data, username: 'You', children: [] });
    setText('');
    setReplying(false);
  };

  return (
    <div className="comment" style={{ marginLeft: comment.parent_id ? 24 : 0 }}>
      <p><strong>{comment.username}</strong> {comment.body}</p>
      <button onClick={() => setReplying(!replying)} className="reply-btn">Reply</button>
      {replying && (
        <div className="reply-form">
          <input value={text} onChange={(e) => setText(e.target.value)}
                 placeholder="Write a reply..." />
          <button onClick={submit}>Send</button>
        </div>
      )}
      {comment.children.map((c) => (
        <CommentItem key={c.id} comment={c} postId={postId} onReply={onReply} />
      ))}
    </div>
  );
}

export default function CommentThread({ comments, postId }: {
  comments: Comment[]; postId: number;
}) {
  const [list, setList] = useState(comments);

  const handleReply = (newComment: Comment) => {
    setList((prev) => addReply(prev, newComment));
  };

  return (
    <div className="comment-thread">
      {list.filter((c) => !c.parent_id).map((c) => (
        <CommentItem key={c.id} comment={c} postId={postId} onReply={handleReply} />
      ))}
    </div>
  );
}

function addReply(comments: Comment[], reply: Comment): Comment[] {
  return comments.map((c) => {
    if (c.id === reply.parent_id) {
      return { ...c, children: [...c.children, reply] };
    }
    return { ...c, children: addReply(c.children, reply) };
  });
}

