from app import socketio

@socketio.on("connect")
def on_connect(auth):
    if not auth or "token" not in auth:
        return False  # reject unauthenticated
    try:
        payload = decode_token(auth["token"])
        user_id = payload["sub"]
        join_room(f"user_{user_id}")
        emit("connected", {"user_id": user_id})
    except Exception:
        return False

import { useEffect, useState } from 'react';
import { io, Socket } from 'socket.io-client';
import { useAuth } from '../context/AuthContext';

interface Notification {
  type: 'like' | 'comment' | 'follow';
  post_id?: number;
  from_user_id: number;
  read: boolean;
}

export function useNotifications() {
  const { accessToken } = useAuth();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [socket, setSocket] = useState<Socket | null>(null);

  useEffect(() => {
    if (!accessToken) return;
    const s = io('http://localhost:5000', { auth: { token: accessToken } });
    s.on('notification', (data: Notification) => {
      setNotifications((prev) => [{ ...data, read: false }, ...prev]);
    });
    setSocket(s);
    return () => { s.disconnect(); };
  }, [accessToken]);

  const markAllRead = () => {
    setNotifications((prev) => prev.map((n) => ({ ...n, read: true })));
  };

  const unreadCount = notifications.filter((n) => !n.read).length;

  return { notifications, unreadCount, markAllRead };
}

import axios from 'axios';

export const api = axios.create({ baseURL: 'http://localhost:5000/api' });

api.interceptors.request.use((config) => {
  const token = localStorage.getItem('access_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

api.interceptors.response.use(
  (res) => res,
  async (error) => {
    const original = error.config;
    if (error.response?.status === 401 && !original._retry) {
      original._retry = true;
      const refresh = localStorage.getItem('refresh_token');
      if (refresh) {
        const res = await axios.post('http://localhost:5000/api/auth/refresh', null, {
          headers: { Authorization: `Bearer ${refresh}` },
        });
        localStorage.setItem('access_token', res.data.access_token);
        original.headers.Authorization = `Bearer ${res.data.access_token}`;
        return api(original);
      }
    }
    return Promise.reject(error);
  }
);
